foreach ($screen in $screens) {
    $cleanTitle = $screen.title -replace '[^a-zA-Z0-9 ]', '' -replace ' ', '_'
    Write-Host "Downloading $($screen.title)..."
    
    # Download Screenshot
    curl.exe --ssl-no-revoke -L $screen.img -o "StitchScreens\$($cleanTitle).png"
    
    # Download Code
    curl.exe --ssl-no-revoke -L $screen.code -o "StitchScreens\$($cleanTitle).html"
}
